import { ZuploContext, ZuploRequest, HttpProblems, environment, ZoneCache } from "@zuplo/runtime";

const CACHE_NAME = "circuit-breaker";

function getCacheKey() {
  const runId = environment.ZEALT_RUN_ID || "default";
  return `cb-state-${runId}`;
}

export async function inbound(
  request: ZuploRequest,
  context: ZuploContext,
  options: any,
  policyName: string
) {
  const cache = new ZoneCache(CACHE_NAME);
  const cacheKey = getCacheKey();

  const state = await cache.get(cacheKey);
  if (state && state.isOpen) {
    context.log.info("Circuit breaker is OPEN. Rejecting request.");
    return HttpProblems.serviceUnavailable(request, context, {
      detail: "Service Unavailable: Circuit breaker is open."
    });
  }

  return request;
}

export async function outbound(
  response: Response,
  request: ZuploRequest,
  context: ZuploContext,
  options: any,
  policyName: string
) {
  const cache = new ZoneCache(CACHE_NAME);
  const cacheKey = getCacheKey();

  if (response.status >= 500) {
    const state = await cache.get(cacheKey) || { failures: 0, isOpen: false };
    state.failures += 1;

    if (state.failures >= 5) {
      state.isOpen = true;
      context.log.error("Circuit breaker tripped! Backend returned 5xx for 5 consecutive requests.");
    }

    await cache.put(cacheKey, state, 60); // cache for 60 seconds
  } else {
    // Reset failures on success
    const state = await cache.get(cacheKey);
    if (state && state.failures > 0) {
      await cache.put(cacheKey, { failures: 0, isOpen: false }, 60);
    }
  }

  return response;
}

